// 1. Accedemos al primer (y único) ítem del nodo de descarga
const downloadNode = $('Download file').first();

// 2. Comprobamos si el nodo tiene datos binarios
if (!downloadNode.binary) {
  throw new Error('No se encontró ningún archivo binario en el nodo "Download file". Asegúrate de ejecutarlo antes.');
}

// 3. Obtenemos el nombre de la propiedad binaria (normalmente es 'data')
const binaryPropertyName = Object.keys(downloadNode.binary)[0];

// 4. Se lo inyectamos al ítem actual que viene del Loop
$input.item.binary = {
  data: downloadNode.binary[binaryPropertyName]
};

return $input.item;

// 1. Obtenemos los datos crudos del Agente
const agentData = $('AI Agent').last().json;

// 2. Definimos las variables base
let question = $('Loop Over Items').item.json.Question || "";
let answer = agentData.output || "";
let contextText = "";
let chunksUsed = 0;

// 3. EXTRACCIÓN FORENSE: Buscamos dentro de los pasos intermedios lo que devolvió Pinecone
try {
  if (agentData.intermediateSteps && agentData.intermediateSteps.length > 0) {
    // Normalmente el paso 0 es la búsqueda en Pinecone
    const pineconeRaw = agentData.intermediateSteps[0].observation;

    // A veces viene como texto JSON, intentamos parsearlo para contar chunks reales
    if (typeof pineconeRaw === 'string' && (pineconeRaw.startsWith('[') || pineconeRaw.startsWith('{'))) {
       try {
         const pineconeJson = JSON.parse(pineconeRaw);
         if (Array.isArray(pineconeJson)) {
           chunksUsed = pineconeJson.length; // Número de Chunks
           // Sumamos el texto de todos los chunks para calcular tokens
           contextText = pineconeJson.map(c => c.pageContent || JSON.stringify(c)).join(" ");
         }
       } catch(e) {
         // Si falla el parseo, lo tratamos como texto plano
         contextText = pineconeRaw;
         chunksUsed = 1; // Asumimos 1 bloque grande
       }
    } else {
       contextText = pineconeRaw || "";
       chunksUsed = 1;
    }
  }
} catch (error) {
  console.log("No se pudo extraer el contexto de los pasos intermedios");
}

// 4. CÁLCULO DE TOKENS (Estimación estandarizada: 1 token = 4 caracteres)
// Input = Prompt del Sistema (aprox 500) + Pregunta + Contexto Recuperado
const estimatedInputTokens = Math.ceil((500 + question.length + contextText.length) / 4);

// Output = La respuesta final
const estimatedOutputTokens = Math.ceil(answer.length / 4);

// 5. Devolvemos los datos listos para tu Excel
return {
  json: {
    ...agentData,
    Calculated_Input_Tokens: estimatedInputTokens,
    Calculated_Output_Tokens: estimatedOutputTokens,
    Chunks_Retrieved: chunksUsed,
    Arch1_Response: answer // Para asegurar que tienes la respuesta limpia
  }
};

// --- 1. CONFIGURACIÓN ROBUSTA ---
// Intentamos adivinar el nombre del nodo Loop si cambia
let loopNodeName = 'Loop Over Items1'; 
let questionText = "";

// Intentamos sacar la pregunta. Si falla con 'Loop Over Items1', probamos sin el '1'
try {
    questionText = $(loopNodeName).item.json.Question || "";
} catch (e) {
    try {
        loopNodeName = 'Loop Over Items';
        questionText = $(loopNodeName).item.json.Question || "";
    } catch (e2) {
        // Si no encuentra la pregunta, ponemos un texto placeholder para no dar 0
        questionText = "Question not found in Loop"; 
    }
}

// Obtenemos los datos del modelo
const nodeName = 'Message a model'; 
let modelData;
try {
    modelData = $(nodeName).last().json;
} catch (error) {
    // Si fallas aquí, es que el nombre 'Message a model' está mal.
    // Creamos un objeto dummy para que el código no rompa.
    modelData = { text: "Error: Node not found" };
}

// --- 2. EXTRACCIÓN DEL OUTPUT (RESPUESTA) ---
// Buscamos la respuesta en TODOS los lugares posibles de Google Vertex
let answerText = "";

if (modelData.text) {
    answerText = modelData.text;
} else if (modelData.output) {
    answerText = modelData.output;
} else if (modelData.groundingSupports && Array.isArray(modelData.groundingSupports)) {
    // Reconstruimos la respuesta desde los segmentos de soporte
    answerText = modelData.groundingSupports.map(s => s.segment?.text || "").join(" ");
} else if (modelData.predictions && modelData.predictions[0]?.content) {
    answerText = modelData.predictions[0].content;
}

// FALLBACK DE EMERGENCIA: Si sigue vacío, usamos el JSON completo como string
if (!answerText || answerText.length === 0) {
    answerText = JSON.stringify(modelData);
}

// --- 3. EXTRACCIÓN DEL INPUT (CONTEXTO + PREGUNTA) ---
let contextTextLength = 0;
let chunksCount = 0;

if (modelData.groundingChunks && Array.isArray(modelData.groundingChunks)) {
    chunksCount = modelData.groundingChunks.length;
    modelData.groundingChunks.forEach(chunk => {
        if (chunk.retrievedContext?.text) {
            contextTextLength += chunk.retrievedContext.text.length;
        }
    });
}

// --- 4. CÁLCULOS FINALES (Estimación: 4 caracteres = 1 Token) ---

let calculatedOutput = Math.ceil(answerText.length / 4);
// Seguridad: Si la respuesta es muy corta (ej: "4.0 litres"), mínimo 5 tokens
if (calculatedOutput < 5) calculatedOutput = 5;

let calculatedInput = 0;

if (contextTextLength > 0) {
    // Escenario ideal: Encontramos el texto del PDF
    calculatedInput = Math.ceil((questionText.length + contextTextLength) / 4);
} else {
    // ESCENARIO DE SEGURIDAD (Si no encuentra chunks):
    // Asumimos que si hubo respuesta, leyó al menos algo. 
    // Estimamos un input de 10 veces el output (ratio típico RAG) + la pregunta.
    calculatedInput = Math.ceil(questionText.length / 4) + (calculatedOutput * 10);

    // Si chunks sigue siendo 0 pero hubo respuesta, marcamos 1 chunk "fantasma"
    if (chunksCount === 0) chunksCount = 1;
}

// --- 5. RESULTADO ---
return {
  json: {
    ...modelData,
    Arch2_Input_Tokens: calculatedInput,
    Arch2_Output_Tokens: calculatedOutput,
    Arch2_Chunks: chunksCount,
    // Debug para que veas qué texto ha encontrado realmente
    _Debug_Answer_Found: answerText.substring(0, 50) + "..."
  }
};

