let inputTokens = modelData.usageMetadata?.promptTokenCount || modelData.usage?.prompt_tokens || 0;
let outputTokens = modelData.usageMetadata?.candidatesTokenCount || modelData.usage?.completion_tokens || 0;


// --- 3. EXTRACCIÓN DEL OUTPUT (RESPUESTA DE LA IA) ---
let answerText = "";

