if (modelData.text && typeof modelData.text === 'string' && modelData.text.length < 5000) { 
    answerText = modelData.text;
} else if (modelData.output) {
    answerText = modelData.output;
} else if (modelData.responses && modelData.responses[0]?.text) {
    answerText = modelData.responses[0].text;
} else if (modelData.content) {
    answerText = modelData.content;
}

// --- CORRECCIÓN DEL ERROR (Blindaje de tipos) ---
// Si answerText es un objeto o null, lo convertimos a String obligatoriamente
if (!answerText) {
    answerText = "Empty response";
} else if (typeof answerText !== 'string') {
    answerText = JSON.stringify(answerText);
}

// Fallback de longitud para no ensuciar el log si es gigante
let previewText = answerText;
if (answerText.length > 500) {
    previewText = answerText.substring(0, 500) + "...";
}

// --- 4. CÁLCULO DE TOKENS ---

// --- 4. CÁLCULO DE TOKENS ---
// OUTPUT (Respuesta)
if (outputTokens === 0) {
    outputTokens = Math.ceil(answerText.length / 4);
    if (outputTokens < 5) outputTokens = 10; 
}
// INPUT (Pregunta)
let chunksCount = 1;
if (inputTokens === 0) {
	// Si la API falla al devolver los metadatos, usamos la deducción empírica.
    let questionTokens = Math.ceil(questionText.length / 4);
	   inputTokens = questionTokens;
}
// --- 5. RESULTADO ---
return {
  json: {
    ...modelData,
    Arch3_Input_Tokens: inputTokens,
